import React, { Component } from "react"

class NotFound extends React.Component {
    render() {
        return (
            <div>
                <h1>Страница не найдена</h1>
                <button onClick={this.props.onAdd}>Войти</button>
            </div>
        )
    }
}

export default NotFound
